const item = $input.first();
const data = item.json;

const tweets = data.tweets || [];

if (tweets.length === 0) {
  return [{ json: { signal: "NO_TRADE", reason: "Nenhum tweet retornado pela API" } }];
}

return tweets.map(function(tweet) {
  return {
    json: {
      id: tweet.id || "",
      text: tweet.text || "",
      author: (tweet.author && tweet.author.userName) || "",
      author_followers: (tweet.author && tweet.author.followers) || 0,
      createdAt: tweet.createdAt || "",
      retweetCount: tweet.retweetCount || 0,
      likeCount: tweet.likeCount || 0,
      viewCount: tweet.viewCount || 0,
      url: tweet.url || "",
      isReply: tweet.isReply || false
    }
  };
});

const item = $input.first();
const tweet = item.json;

if (tweet.signal === "NO_TRADE") { return [item]; }

const createdAt = tweet.createdAt || "";
if (createdAt) {
  const tweetDate = new Date(createdAt);
  const minutesAgo = (Date.now() - tweetDate.getTime()) / 60000;
  if (minutesAgo > 35) {
    return [{ json: { signal: "NO_TRADE", reason: "Tweet mais antigo que 35 minutos (" + Math.round(minutesAgo) + "min)" } }];
  }
}

return [{
  json: {
    news_text: tweet.text || "",
    tweet_id: tweet.id || "",
    tweet_url: tweet.url || "",
    author: tweet.author || "",
    author_followers: tweet.author_followers || 0,
    timestamp: new Date().toISOString()
  }
}];

const item = $input.first();
const data = item.json;

function sanitize(text) {
  return (text || "")
    .replace(/https?:\/\/\S+/g, "")
    .replace(/\*/g, "")
    .replace(/[\uD800-\uDFFF]/g, "")
    .replace(/\s+/g, " ")
    .trim();
}

const tweetText = sanitize(data.news_text);
const author = data.author || "";
const followers = data.author_followers || 0;

const prompt = `You are a Polymarket prediction market expert. Analyze this tweet and determine if it contains breaking news that would affect prediction markets.

Tweet: "${tweetText}"
Author: @${author} (${followers} followers)

TASK: If this tweet reports a real-world event relevant to prediction markets (elections, policy decisions, geopolitical events, economic announcements, regulatory changes, conflicts, etc.), respond with the best 2-5 word Polymarket search query that will find the most relevant active markets.

RULES for your query:
- Use 2 to 5 words minimum
- Use full English words only — no abbreviations, no ticker symbols, no acronyms
- Never use ALL CAPS words (write 'bitcoin' not 'BTC' or 'BIT', 'federal reserve' not 'FED', 'artificial intelligence' not 'AI')
- Be specific: combine the actor + action or topic + context
- Focus on the event, not the asset price

If the tweet is a reply, personal opinion, joke, insult, spam, or does NOT relate to any verifiable event that prediction markets would track, respond with exactly: NO_TRADE

Examples of GOOD queries: fed rate cut, iran nuclear deal, trump china tariff, ukraine russia ceasefire, bitcoin etf approval, israel iran attack
Examples of BAD queries (never do this): BIT, BTC, FED, AI, Iran, Trump, Bitcoin

Respond with ONLY the search query or NO_TRADE. Nothing else.`;

return [{ json: { ...data, ai_prompt: prompt } }];

const item = $input.first();
const response = item.json;
const newsData = $('Preparar Prompt IA').first().json;

let aiQuery = (response.text || response.response || response.output || "").trim();
aiQuery = aiQuery.replace(/[\"']/g, "").replace(/\s+/g, " ").trim();

if (!aiQuery || aiQuery.toUpperCase().startsWith("NO_") || aiQuery.toUpperCase() === "NO") {
  return [{ json: { signal: "NO_TRADE", reason: "LLM determinou que o tweet nao e relevante para mercados de predicao" } }];
}

return [{
  json: {
    news_text: newsData.news_text,
    tweet_id: newsData.tweet_id,
    tweet_url: newsData.tweet_url,
    author: newsData.author,
    author_followers: newsData.author_followers,
    search_query: aiQuery,
    ai_query: aiQuery,
    timestamp: newsData.timestamp
  }
}];

const newsData = $('Extrair Query IA').first().json;
const responseData = $input.first().json;

// public-search retorna { events: [...], pagination: {...} }
const events = responseData.events || [];

// Extrair todos os mercados dos eventos
let allMarkets = [];
for (const event of events) {
  if (event.archived) continue;
  const eventMarkets = event.markets || [];
  for (const market of eventMarkets) {
    if (market.active === false || market.closed === true || market.archived === true) continue;
    allMarkets.push(Object.assign({}, market, {
      eventSlug: event.slug,
      eventTitle: event.title
    }));
  }
}

// Filtrar por volume > $500
allMarkets = allMarkets.filter(function(m) {
  return parseFloat(m.volumeNum || m.volume || 0) > 500;
});

if (allMarkets.length === 0) {
  return [{ json: {
    signal: 'NO_TRADE',
    reason: 'Nenhum mercado ativo encontrado para: ' + (newsData.ai_query || newsData.search_query || ''),
    news_text: newsData.news_text,
    tweet_id: newsData.tweet_id,
    author: newsData.author,
    author_followers: newsData.author_followers,
    ai_query: newsData.ai_query
  } }];
}

const queryWords = (newsData.ai_query || '').toLowerCase().split(/\s+/).filter(function(w) { return w.length > 2; });
const threshold = queryWords.length >= 3 ? 2 : 1;

const filtered = allMarkets
  .filter(function(m) {
    if (queryWords.length === 0) return true;
    const text = [
      m.question || '',
      (m.description || '').substring(0, 300),
      m.eventTitle || '',
      m.groupItemTitle || ''
    ].join(' ').toLowerCase();
    const matchCount = queryWords.filter(function(word) { return text.includes(word); }).length;
    return matchCount >= threshold;
  })
  .sort(function(a, b) {
    return parseFloat(b.volumeNum || b.volume || 0) - parseFloat(a.volumeNum || a.volume || 0);
  })
  .slice(0, 5);

if (filtered.length === 0) {
  return [{ json: {
    signal: 'NO_TRADE',
    reason: 'Nenhum mercado passou no filtro de relevancia para: ' + (newsData.ai_query || ''),
    news_text: newsData.news_text,
    tweet_id: newsData.tweet_id,
    author: newsData.author,
    author_followers: newsData.author_followers,
    ai_query: newsData.ai_query
  } }];
}

return [{ json: {
  markets: filtered,
  market_count: filtered.length,
  news_text: newsData.news_text,
  tweet_id: newsData.tweet_id,
  tweet_url: newsData.tweet_url,
  author: newsData.author,
  author_followers: newsData.author_followers,
  ai_query: newsData.ai_query,
  timestamp: newsData.timestamp
} }];

const item = $input.first();
const data = item.json;

if (data.signal === "NO_TRADE") { return [item]; }

const markets = data.markets || [];
if (markets.length === 0) {
  return [{ json: { signal: "NO_TRADE", reason: "Lista de mercados vazia" } }];
}

const top = markets[0];
const news = data.news_text || "";

function esc(text) {
  return (text || "").replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;");
}

let yesPrice = 0.5;
try {
  const prices = typeof top.outcomePrices === "string"
    ? JSON.parse(top.outcomePrices)
    : (top.outcomePrices || []);
  yesPrice = parseFloat(prices[0] || 0.5);
} catch(e) {}

const volume = parseFloat(top.volumeNum || top.volume || 0);
const yesPct = Math.round(yesPrice * 100);

let direction, expectedTo, confidence;
if (yesPrice <= 0.30) {
  direction = "BUY_YES";
  expectedTo = Math.min(yesPct + 20, 95);
  confidence = 70;
} else if (yesPrice >= 0.70) {
  direction = "BUY_NO";
  expectedTo = Math.max(yesPct - 20, 5);
  confidence = 68;
} else {
  direction = "BUY_YES";
  expectedTo = Math.min(yesPct + 12, 95);
  confidence = 60;
}

if (volume > 100000) confidence = Math.min(confidence + 8, 88);
if (volume > 500000) confidence = Math.min(confidence + 5, 88);

const followers = data.author_followers || 0;
if (followers > 100000) confidence = Math.min(confidence + 5, 88);

const eventSlug = top.eventSlug || (top.events && top.events[0] && top.events[0].slug) || "";
const marketSlug = top.slug || "";
let marketUrl;
if (eventSlug && marketSlug) {
  marketUrl = "https://polymarket.com/event/" + eventSlug + "/" + marketSlug;
} else if (eventSlug) {
  marketUrl = "https://polymarket.com/event/" + eventSlug;
} else if (marketSlug) {
  marketUrl = "https://polymarket.com/event/" + marketSlug;
} else if (top.id) {
  marketUrl = "https://polymarket.com/markets?id=" + top.id;
} else {
  marketUrl = "https://polymarket.com/markets?search=" + encodeURIComponent(data.ai_query || "");
}
const question = esc(top.question || top.title || "N/A");
const newsSummary = esc(news.length > 120 ? news.substring(0, 120) + "..." : news);
const authorInfo = data.author ? "@" + esc(data.author) : "fonte desconhecida";
const aiQueryInfo = data.ai_query ? "\n\uD83E\uDD16 <b>Query IA:</b> <code>" + esc(data.ai_query) + "</code>" : "";

const msg = "🚨 <b>ALERTA DE TRADE - POLYMARKET</b>\n\n"
  + "🐦 <b>Tweet de " + authorInfo + ":</b>\n" + newsSummary + "\n\n"
  + "📊 <b>Mercado:</b>\n" + question + "\n\n"
  + "🎯 <b>Direcao:</b> <code>" + direction + "</code>\n"
  + "💪 <b>Confianca:</b> " + confidence + "%\n"
  + "📈 <b>Movimento:</b> " + yesPct + "% \u2192 " + expectedTo + "%\n"
  + "💰 <b>Volume:</b> $" + Math.round(volume).toLocaleString("en-US") + aiQueryInfo + "\n\n"
  + "🐦 " + (data.tweet_url || "") + "\n"
  + "🔗 " + marketUrl;

return [{ json: {
  signal: "TRADE",
  market_id: top.id || "",
  market_question: question,
  market_url: marketUrl,
  direction: direction,
  confidence: confidence,
  expected_from: yesPct,
  expected_to: expectedTo,
  current_price_yes: yesPct,
  volume: volume,
  news_summary: newsSummary,
  tweet_id: data.tweet_id || "",
  tweet_url: data.tweet_url || "",
  author: data.author || "",
  author_followers: data.author_followers || 0,
  ai_query: data.ai_query || "",
  telegram_message: msg,
  timestamp: new Date().toISOString()
} }];
